"""Core 100 ORB Residential Quality Lab scenarios — synthetic anonymised only."""

from __future__ import annotations

from typing import Any

from assistant.evals.orb_residential_scenario_schema import (
    DEFAULT_PROHIBITED_ELEMENTS,
    DEFAULT_REQUIRED_ELEMENTS,
    SAFEGUARDING_REQUIRED_ELEMENTS,
    SCHEMA_VERSION,
)

_COMMON_PROHIBITED = DEFAULT_PROHIBITED_ELEMENTS
_COMMON_REQUIRED = DEFAULT_REQUIRED_ELEMENTS


def _core(
    num: int,
    title: str,
    *,
    record_type: str,
    feature_target: str,
    difficulty: str,
    regulatory_context: str | list[str],
    scenario_family: str,
    input_text: str,
    expected_strengths: list[str] | None = None,
    required_elements: list[str] | None = None,
    prohibited_elements: list[str] | None = None,
    safeguarding_flags: list[str] | None = None,
    quality_focus: str = "",
    ideal_output_traits: list[str] | None = None,
    scoring_notes: str = "",
    source: str = "core100_generator",
    baseline_id: str | None = None,
) -> dict[str, Any]:
    sid = f"core_{num:03d}"
    reg = regulatory_context if isinstance(regulatory_context, list) else [regulatory_context]
    return {
        "scenario_id": sid,
        "title": title,
        "version": SCHEMA_VERSION,
        "source": source,
        "scenario_family": scenario_family,
        "record_type": record_type,
        "feature_target": feature_target,
        "difficulty": difficulty,
        "regulatory_context": reg,
        "input": input_text,
        "expected_strengths": expected_strengths or ["factual observations", "adult response", "outcome"],
        "required_elements": required_elements or list(_COMMON_REQUIRED),
        "prohibited_elements": prohibited_elements or list(_COMMON_PROHIBITED),
        "safeguarding_flags": safeguarding_flags or [],
        "quality_focus": quality_focus or title,
        "ideal_output_traits": ideal_output_traits or ["structured headings", "missing information marked", "respectful tone"],
        "scoring_notes": scoring_notes or "Synthetic residential childcare recording scenario.",
        "synthetic_data_confirmation": True,
        "baseline_id": baseline_id,
    }


